),
"Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Observation' AND fhirpath_bool(r.resource, 'code.coding.where(system=''http://loinc.org'' and code=''71007-9'').exists()')
),
"Condition: Pervasive Developmental Disorder (qicore-condition-problems-health-concerns)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Condition' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.464.1003.105.12.1152') AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-problems-health-concerns')
),
"Coverage: Payer Type" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'type') AS "type" FROM resources r WHERE r.resourceType = 'Coverage' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.114222.4.11.3591')
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Denominator Identification Period" AS (
SELECT p.patient_id, intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 14.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 2.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE) AS value FROM _patients AS p
),
"Depression Assessments Greater Than 9" AS (
SELECT * FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'value')), '{') THEN json_extract_string(fhirpath_text(DepressionAssessment.resource, 'value'), '$.value') ELSE fhirpath_text(DepressionAssessment.resource, 'value') END AS DOUBLE) > 9 AND array_contains(['final', 'amended', 'corrected'], DepressionAssessment.status)
),
"Depression Diagnoses" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Major Depression Including Remission (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Major Depression Including Remission (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Dysthymia (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Dysthymia (qicore-condition-encounter-diagnosis)") AS Depression WHERE (fhirpath_bool(Depression.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(Depression.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(Depression.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(Depression.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()')
),
"Depression Encounter" AS (
SELECT * FROM "Encounter: Contact or Office Visit" AS ValidEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Depression Diagnoses") AS Depression WHERE intervalOverlaps(fhirpath_text(ValidEncounter.resource, 'period'), CASE WHEN fhirpath_text(Depression.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), fhirpath_text(Depression.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(Depression.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AND CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE) AND COALESCE(CAST(intervalEnd((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE), CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE)) AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished' AND Depression.patient_id = ValidEncounter.patient_id)
),
"Index Depression Assessment" AS (
SELECT p.patient_id, (SELECT resource FROM "Depression Assessments Greater Than 9" AS DepressionAssessment WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Depression Encounter") AS DepressionEncounter WHERE CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) >= CAST(CASE WHEN typeof(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(DepressionEncounter.resource, 'period')) AS VARCHAR), '{"value": 7.0, "unit": "day", "system": "http://unitsofmeasure.org"}')) = 'VARCHAR' AND NOT (dateSubtractQuantity(CAST(intervalStart(fhirpath_text(DepressionEncounter.resource, 'period')) AS VARCHAR), '{"value": 7.0, "unit": "day", "system": "http://unitsofmeasure.org"}')) SIMILAR TO '\d{4}-\d{2}-\d{2}.*' THEN NULL ELSE TRY_CAST((dateSubtractQuantity(CAST(intervalStart(fhirpath_text(DepressionEncounter.resource, 'period')) AS VARCHAR), '{"value": 7.0, "unit": "day", "system": "http://unitsofmeasure.org"}')) AS DATE) END AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(intervalEnd(fhirpath_text(DepressionEncounter.resource, 'period')) AS DATE) AND DepressionEncounter.patient_id = DepressionAssessment.patient_id) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) ASC NULLS LAST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST(intervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST(intervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST(intervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(intervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 12
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Measure Assessment Period" AS (
SELECT FirstIndexAssessment.patient_id, intervalFromBounds(CAST(dateSubtractQuantity(CAST(dateAddQuantity(CAST(intervalStart(CASE WHEN fhirpath_text(FirstIndexAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstIndexAssessment.resource, 'effective')), '{') THEN fhirpath_text(FirstIndexAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FirstIndexAssessment.resource, 'effective'), fhirpath_text(FirstIndexAssessment.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), '{"value": 12.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), '{"value": 60.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateAddQuantity(CAST(dateAddQuantity(CAST(intervalStart(CASE WHEN fhirpath_text(FirstIndexAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FirstIndexAssessment.resource, 'effective')), '{') THEN fhirpath_text(FirstIndexAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FirstIndexAssessment.resource, 'effective'), fhirpath_text(FirstIndexAssessment.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), '{"value": 12.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), '{"value": 60.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE) AS value FROM "Index Depression Assessment" AS FirstIndexAssessment
),
"Has Hospice Services in the Measure Assessment Period" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Measure Assessment Period" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Encounter: Encounter Inpatient" AS InpatientEncounter WHERE InpatientEncounter.patient_id = p.patient_id AND (fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428361000124107'').exists()') OR fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428371000124100'').exists()')) AND CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE)) AND fhirpath_text(InpatientEncounter.resource, 'status') = 'finished') OR EXISTS (SELECT * FROM "Encounter: Hospice Encounter" AS HospiceEncounter WHERE HospiceEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['cancelled', 'entered-in-error', 'unknown'], fhirpath_text(HospiceEncounter.resource, 'status'))) OR EXISTS (SELECT * FROM "Observation: Hospice care [Minimum Data Set]" AS HospiceAssessment WHERE HospiceAssessment.patient_id = p.patient_id AND fhirpath_bool(HospiceAssessment.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''373066001'').exists()') AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(HospiceAssessment.resource, 'status'))) OR EXISTS (SELECT * FROM "ServiceRequest: Hospice Care Ambulatory" AS HospiceOrder WHERE HospiceOrder.patient_id = p.patient_id AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) <= CAST(intervalEnd(j1.value) AS DATE) AND array_contains(['active', 'completed'], fhirpath_text(HospiceOrder.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(HospiceOrder.resource, 'intent')) AND fhirpath_text(HospiceOrder.resource, 'doNotPerform') IS NOT TRUE) OR EXISTS (SELECT * FROM "Procedure: Hospice Care Ambulatory" AS HospicePerformed WHERE HospicePerformed.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['not-done', 'entered-in-error', 'unknown'], fhirpath_text(HospicePerformed.resource, 'status'))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-encounter-diagnosis)") AS HospiceCareDiagnosis WHERE HospiceCareDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND (fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HospiceCareDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Mental Health Disorder Diagnoses" AS (
