erDiagnoses.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) = 'VARCHAR' AND NOT (intervalStart(CASE WHEN fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MentalHealthDisorderDiagnoses.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), f