 WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['not-done', 'entered-in-error', 'unknown'], fhirpath_text(PalliativeIntervention.resource, 'status')))
),
