ment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END)) SIMILAR TO '\d{4}-\d{2}-\d{2}.*' THEN NULL ELSE TRY_CAST((intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END)) AS DATE) END AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(DepressionAssessment.resource, 'status')) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value'), '$.value') ELSE fhirpath_text((SELECT resource FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE CAST(CASE WHEN typeof(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{'